--
-- Table structure for table `task_efficiency`
--

DROP TABLE IF EXISTS `task_efficiency`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `task_efficiency` (
  `id` int NOT NULL AUTO_INCREMENT,
  `task_id` int NOT NULL,
  `phase` varchar(50) NOT NULL,
  `assignee_id` int DEFAULT NULL,
  `standard_hours` decimal(10,2) NOT NULL DEFAULT '0.00',
  `actual_work_hours` decimal(10,2) NOT NULL DEFAULT '0.00',
  `exception_hours` decimal(10,2) NOT NULL DEFAULT '0.00',
  `assist_hours` decimal(10,2) NOT NULL DEFAULT '0.00',
  `efficiency` decimal(10,2) NOT NULL DEFAULT '0.00',
  `phase_start_time` datetime DEFAULT NULL,
  `phase_end_time` datetime DEFAULT NULL,
  `is_confirmed` tinyint(1) NOT NULL DEFAULT '0',
  `confirmed_by` int DEFAULT NULL,
  `confirmed_at` datetime DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_task_phase_confirm` (`task_id`,`phase`),
  KEY `assignee_id` (`assignee_id`),
  KEY `confirmed_by` (`confirmed_by`),
  CONSTRAINT `task_efficiency_ibfk_1` FOREIGN KEY (`task_id`) REFERENCES `tasks` (`id`),
  CONSTRAINT `task_efficiency_ibfk_2` FOREIGN KEY (`assignee_id`) REFERENCES `users` (`id`),
  CONSTRAINT `task_efficiency_ibfk_3` FOREIGN KEY (`confirmed_by`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=709 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

